# encoding: UTF-8
class SessionsController < ApplicationController

  CONN = ActiveRecord::Base.connection

def new
  if current_user
    redirect_to days_path, :notice => t(:welcome_back)
  end 
end

def create
  user = User.authenticate(params[:email], params[:password])
  if user
    session[:user_id] = user.id
    redirect_to root_path, :notice => t(:logged_in)
  else
    flash.now.alert = t(:invalid_user)
    render "new"
  end
end

def destroy
  session[:user_id] = nil
  redirect_to log_in_path, :notice => t(:logged_out)
end


def load
 if current_user && current_user.admin
CONN.execute "DELETE from dictitems"  

CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Плечи - Жим штанги из-за головы сидя', 'http://bodysportal.com/bodibilding/uprazhneniya/plechi/zhim-shtangi-iz-za-golovy-sidya', 'Это упражнение нагружает в основном средние пучки дельтовидных мышц и верхнюю часть трапециевидных мышц.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesShoulder/miniDelts01.jpg', 'Плечи - Жим штанги из-за головы сидя', 'http://bodysportal.com/bodibilding/uprazhneniya/plechi/zhim-shtangi-iz-za-golovy-sidya', 'Это упражнение нагружает в основном средние пучки дельтовидных мышц и верхнюю часть трапециевидных мышц.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesShoulder/miniDelts01.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Плечи - Жим гантелей сидя', 'http://bodysportal.com/bodibilding/uprazhneniya/plechi/zhim-gantelej-sidya', 'Это упражнение, прежде всего, предназначено для тренинга средних частей дельтовидных мышц, а также верхних отделов трапециевидных мышц, передних зубчатых мышц и трицепсов.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesShoulder/miniDelts03.jpg', 'Плечи - Жим гантелей сидя', 'http://bodysportal.com/bodibilding/uprazhneniya/plechi/zhim-gantelej-sidya', 'Это упражнение, прежде всего, предназначено для тренинга средних частей дельтовидных мышц, а также верхних отделов трапециевидных мышц, передних зубчатых мышц и трицепсов.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesShoulder/miniDelts03.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Плечи - Подъемы гантелей в стороны', 'http://bodysportal.com/bodibilding/uprazhneniya/plechi/pod-emy-gantelej-v-storony', 'Это упражнение развивает среднюю часть дельтовидной мышцы, состоящую из нескольких пучков, прикрепляющихся к плечевой кости.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesShoulder/miniDelts06.jpg', 'Плечи - Подъемы гантелей в стороны', 'http://bodysportal.com/bodibilding/uprazhneniya/plechi/pod-emy-gantelej-v-storony', 'Это упражнение развивает среднюю часть дельтовидной мышцы, состоящую из нескольких пучков, прикрепляющихся к плечевой кости.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesShoulder/miniDelts06.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Плечи - Подъем гантели в сторону одной рукой лежа на боку', 'http://bodysportal.com/bodibilding/uprazhneniya/plechi/pod-em-ganteli-v-storonu-odnoj-rukoj-lezha-na-boku', 'При выполнении этого упражнения основное усилие концентрируется уже в начале движения. Лучших результатов можно достичь, делая 10-20 повторений.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesShoulder/miniDelts08.jpg', 'Плечи - Подъем гантели в сторону одной рукой лежа на боку', 'http://bodysportal.com/bodibilding/uprazhneniya/plechi/pod-em-ganteli-v-storonu-odnoj-rukoj-lezha-na-boku', 'При выполнении этого упражнения основное усилие концентрируется уже в начале движения. Лучших результатов можно достичь, делая 10-20 повторений.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesShoulder/miniDelts08.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Плечи - Подъем одной руки в сторону с нижнего блока', 'http://bodysportal.com/bodibilding/uprazhneniya/plechi/pod-em-odnoj-ruki-v-storonu-s-nizhnego-bloka', 'Это упражнение развивает дельтовидную мышцу, особенно ее среднюю многоперистую часть, состоящую из нескольких пучков в форме пера.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesShoulder/miniDelts09.jpg', 'Плечи - Подъем одной руки в сторону с нижнего блока', 'http://bodysportal.com/bodibilding/uprazhneniya/plechi/pod-em-odnoj-ruki-v-storonu-s-nizhnego-bloka', 'Это упражнение развивает дельтовидную мышцу, особенно ее среднюю многоперистую часть, состоящую из нескольких пучков в форме пера.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesShoulder/miniDelts09.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Плечи - Плечевая передняя протяжка', 'http://bodysportal.com/bodibilding/uprazhneniya/plechi/plechevaya-perednyaya-protyazhka', 'Стоя. Ноги врозь. Спина прямая. Гриф штанги держать внизу у бедер, взяв ее чуть шире плеч хватом сверху.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesShoulder/miniDelts15.jpg', 'Плечи - Плечевая передняя протяжка', 'http://bodysportal.com/bodibilding/uprazhneniya/plechi/plechevaya-perednyaya-protyazhka', 'Стоя. Ноги врозь. Спина прямая. Гриф штанги держать внизу у бедер, взяв ее чуть шире плеч хватом сверху.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesShoulder/miniDelts15.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Плечи - Подъемы рук в стороны на тренажере', 'http://bodysportal.com/bodibilding/uprazhneniya/plechi/pod-emy-ruk-v-storony-na-trenazhere', 'Это упражнение главным образом воздействует на среднюю часть дельтовидных мышц. Дополнительно влияет на надостные мышцы и верхнюю часть трапециевидных мышц при подъеме рук выше горизонтального уровня.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesShoulder/miniDelts16.jpg', 'Плечи - Подъемы рук в стороны на тренажере', 'http://bodysportal.com/bodibilding/uprazhneniya/plechi/pod-emy-ruk-v-storony-na-trenazhere', 'Это упражнение главным образом воздействует на среднюю часть дельтовидных мышц. Дополнительно влияет на надостные мышцы и верхнюю часть трапециевидных мышц при подъеме рук выше горизонтального уровня.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesShoulder/miniDelts16.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Плечи - Жим штанги с груди сидя', 'http://bodysportal.com/bodibilding/uprazhneniya/plechi/zhim-shtangi-s-grudi-sidya', 'Чтобы увеличить нагрузку на передние части дельтовидных мышц, заведите локти слегка вперед.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesShoulder/miniDelts02.jpg', 'Плечи - Жим штанги с груди сидя', 'http://bodysportal.com/bodibilding/uprazhneniya/plechi/zhim-shtangi-s-grudi-sidya', 'Чтобы увеличить нагрузку на передние части дельтовидных мышц, заведите локти слегка вперед.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesShoulder/miniDelts02.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Плечи - Жим гантелей с поворотами запястий', 'http://bodysportal.com/bodibilding/uprazhneniya/plechi/poperemennyj-zhim-gantelej-s-povorotami-zapyastij', 'Это упражнение рекомендовано делать людям с хрупкими плечами. Оно заменяет упражнения, нередко приводящие к травмам, например, классический жим с гантелями с отведенными наружу локтями или жим штанги из-за головы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesShoulder/miniDelts04.jpg', 'Плечи - Жим гантелей с поворотами запястий', 'http://bodysportal.com/bodibilding/uprazhneniya/plechi/poperemennyj-zhim-gantelej-s-povorotami-zapyastij', 'Это упражнение рекомендовано делать людям с хрупкими плечами. Оно заменяет упражнения, нередко приводящие к травмам, например, классический жим с гантелями с отведенными наружу локтями или жим штанги из-за головы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesShoulder/miniDelts04.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Плечи - Подъемы гантелей вперед попеременно', 'http://bodysportal.com/bodibilding/uprazhneniya/plechi/pod-emy-gantelej-vpered-poperemenno', 'Это упражнение воздействует главным образом на переднюю часть дельтовидной мышцы, ключичную часть большой грудной мышцы и в меньшей степени на среднюю часть дельтовидной мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesShoulder/miniDelts07.jpg', 'Плечи - Подъемы гантелей вперед попеременно', 'http://bodysportal.com/bodibilding/uprazhneniya/plechi/pod-emy-gantelej-vpered-poperemenno', 'Это упражнение воздействует главным образом на переднюю часть дельтовидной мышцы, ключичную часть большой грудной мышцы и в меньшей степени на среднюю часть дельтовидной мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesShoulder/miniDelts07.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Плечи - Подъем одной руки вперед с нижнего блока стоя', 'http://bodysportal.com/bodibilding/uprazhneniya/plechi/pod-em-odnoj-ruki-vpered-s-nizhnego-bloka-stoya', 'Стоя. Ноги слегка расставить. Рукоятку тренажера взять хватом сверху, держа руку сбоку у бедра.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesShoulder/miniDelts10.jpg', 'Плечи - Подъем одной руки вперед с нижнего блока стоя', 'http://bodysportal.com/bodibilding/uprazhneniya/plechi/pod-em-odnoj-ruki-vpered-s-nizhnego-bloka-stoya', 'Стоя. Ноги слегка расставить. Рукоятку тренажера взять хватом сверху, держа руку сбоку у бедра.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesShoulder/miniDelts10.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Плечи - Подъемы рук вперед с одной гантелью', 'http://bodysportal.com/bodibilding/uprazhneniya/plechi/pod-emy-ruk-vpered-s-odnoj-gantelyu', 'Это упражнение задействует переднюю часть дельтовидных мышц, ключичную часть большой грудной мышцы и короткую головку бицепсов.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesShoulder/miniDelts13.jpg', 'Плечи - Подъемы рук вперед с одной гантелью', 'http://bodysportal.com/bodibilding/uprazhneniya/plechi/pod-emy-ruk-vpered-s-odnoj-gantelyu', 'Это упражнение задействует переднюю часть дельтовидных мышц, ключичную часть большой грудной мышцы и короткую головку бицепсов.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesShoulder/miniDelts13.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Плечи - Подъемы штанги вперед', 'http://bodysportal.com/bodibilding/uprazhneniya/plechi/pod-emy-shtangi-vpered', 'Это упражнение задействует переднюю часть дельтовидных мышц, поднимая штангу выше уровня плеч, вы усилите нагрузку на заднюю часть дельтовидной мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesShoulder/miniDelts14.jpg', 'Плечи - Подъемы штанги вперед', 'http://bodysportal.com/bodibilding/uprazhneniya/plechi/pod-emy-shtangi-vpered', 'Это упражнение задействует переднюю часть дельтовидных мышц, поднимая штангу выше уровня плеч, вы усилите нагрузку на заднюю часть дельтовидной мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesShoulder/miniDelts14.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Плечи - Подъемы гантелей в стороны в наклоне вперед', 'http://bodysportal.com/bodibilding/uprazhneniya/plechi/pod-emy-gantelej-v-storony-v-naklone-vpered', 'Это упражнение в основном задействует заднюю часть дельтовидных мышц.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesShoulder/miniDelts05.jpg', 'Плечи - Подъемы гантелей в стороны в наклоне вперед', 'http://bodysportal.com/bodibilding/uprazhneniya/plechi/pod-emy-gantelej-v-storony-v-naklone-vpered', 'Это упражнение в основном задействует заднюю часть дельтовидных мышц.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesShoulder/miniDelts05.jpg')"
