CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Плечи - Махи руками назад с рукоятками тренажера', 'http://bodysportal.com/bodibilding/uprazhneniya/plechi/makhi-rukami-nazad-s-rukoyatkami-trenazhera', 'Это упражнение прорабатывает дельтовидные мышцы, особенно заднюю часть, подостную мышцу, малую круглую мышцу.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesShoulder/miniDelts17.jpg', 'Плечи - Махи руками назад с рукоятками тренажера', 'http://bodysportal.com/bodibilding/uprazhneniya/plechi/makhi-rukami-nazad-s-rukoyatkami-trenazhera', 'Это упражнение прорабатывает дельтовидные мышцы, особенно заднюю часть, подостную мышцу, малую круглую мышцу.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesShoulder/miniDelts17.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Шея - Подъемы головы лежа спиной на скамье', 'http://bodysportal.com/bodibilding/uprazhneniya/neck/pod-emy-golovy-lezha-spinoj-na-skame', 'Наиболее эффективное упражнение для мышц передней части шеи - грудино-ключично-сосцевидной, грудино-подъязычной и лестничной мышц.', 'http://bodysportal.com/images/bodibilding/exercises/neck/neckFront.jpg', 'Шея - Подъемы головы лежа спиной на скамье', 'http://bodysportal.com/bodibilding/uprazhneniya/neck/pod-emy-golovy-lezha-spinoj-na-skame', 'Наиболее эффективное упражнение для мышц передней части шеи - грудино-ключично-сосцевидной, грудино-подъязычной и лестничной мышц.', 'http://bodysportal.com/images/bodibilding/exercises/neck/neckFront.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Шея - Подъемы головы лежа на скамье лицом вниз', 'http://bodysportal.com/bodibilding/uprazhneniya/neck/pod-emy-golovy-lezha-na-skame-litsom-vniz', 'Это упражнение задействует мышцы задней части шеи. Трапециевидные, грудино-ключично-сосцевидные, лестничные, полуостистая и пластырная.', 'http://bodysportal.com/images/bodibilding/exercises/neck/neckBack.jpg', 'Шея - Подъемы головы лежа на скамье лицом вниз', 'http://bodysportal.com/bodibilding/uprazhneniya/neck/pod-emy-golovy-lezha-na-skame-litsom-vniz', 'Это упражнение задействует мышцы задней части шеи. Трапециевидные, грудино-ключично-сосцевидные, лестничные, полуостистая и пластырная.', 'http://bodysportal.com/images/bodibilding/exercises/neck/neckBack.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Шея - Боковые подъемы головы лежа', 'http://bodysportal.com/bodibilding/uprazhneniya/neck/bokovye-pod-emy-golovy-lezha', 'Эффективно включаются в работу боковые мышцы шеи: грудино-ключично-сосцевидные, лестничные, пластырные, полуостистые мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/neck/neckSide.jpg', 'Шея - Боковые подъемы головы лежа', 'http://bodysportal.com/bodibilding/uprazhneniya/neck/bokovye-pod-emy-golovy-lezha', 'Эффективно включаются в работу боковые мышцы шеи: грудино-ключично-сосцевидные, лестничные, пластырные, полуостистые мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/neck/neckSide.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Спина - Подтягивания на специальной перекладине', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/podtyagivaniya-na-spetsialnoj-perekladine', 'Это упражнение требует определенной физической силы и прекрасно подходит для развития широчайшей мышцы спины, большой круглой мышцы и, в момент сведения лопаток в конце подтягивания, ромбовидных мышц.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack02.jpg', 'Спина - Подтягивания на специальной перекладине', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/podtyagivaniya-na-spetsialnoj-perekladine', 'Это упражнение требует определенной физической силы и прекрасно подходит для развития широчайшей мышцы спины, большой круглой мышцы и, в момент сведения лопаток в конце подтягивания, ромбовидных мышц.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack02.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Спина - Подтягивания на перекладине хватом снизу', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/podtyagivaniya-na-perekladine-khvatom-snizu', 'Это движение развивает широчайшую мышцу и большую круглую мышцу спины. Его усилия распространяются также на бицепсы и плечевые мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack01.jpg', 'Спина - Подтягивания на перекладине хватом снизу', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/podtyagivaniya-na-perekladine-khvatom-snizu', 'Это движение развивает широчайшую мышцу и большую круглую мышцу спины. Его усилия распространяются также на бицепсы и плечевые мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack01.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Спина - Тяги верхнего блока перед собой', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/tyagi-verkhnego-bloka-pered-soboj', 'Это упражнение наращивает ширину спины, задействует трапециевидную мышцу, ромбовидные мышцы, бицепсы и плечевые мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack03.jpg', 'Спина - Тяги верхнего блока перед собой', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/tyagi-verkhnego-bloka-pered-soboj', 'Это упражнение наращивает ширину спины, задействует трапециевидную мышцу, ромбовидные мышцы, бицепсы и плечевые мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack03.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Спина - Тяги верхнего блока за шею', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/tyagi-verkhnego-bloka-za-sheyu', 'Это упражнение превосходно развивает ширину спины, ее верхние и нижние пучки, а также большие круглые мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack04.jpg', 'Спина - Тяги верхнего блока за шею', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/tyagi-verkhnego-bloka-za-sheyu', 'Это упражнение превосходно развивает ширину спины, ее верхние и нижние пучки, а также большие круглые мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack04.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Спина - Тяги верхнего блока узким хватом', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/tyagi-verkhnego-bloka-uzkim-khvatom', 'Это превосходное упражнение для полного развития широчайшей мышцы спины и большой круглой мышцы. При сведении лопаток задействуются ромбовидная и трапециевидная мышцы, а также задние части дельтовидной мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack05.jpg', 'Спина - Тяги верхнего блока узким хватом', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/tyagi-verkhnego-bloka-uzkim-khvatom', 'Это превосходное упражнение для полного развития широчайшей мышцы спины и большой круглой мышцы. При сведении лопаток задействуются ромбовидная и трапециевидная мышцы, а также задние части дельтовидной мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack05.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Спина - Тяги верхнего блока прямыми руками', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/tyagi-verkhnego-bloka-pryamymi-rukami', 'Это упражнение также задействует широчайшие и круглые мышцы спины. Пловцы часто используют это упражнение как силовое, позволяющее им получать хорошие результаты в стиле кроль.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack06.jpg', 'Спина - Тяги верхнего блока прямыми руками', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/tyagi-verkhnego-bloka-pryamymi-rukami', 'Это упражнение также задействует широчайшие и круглые мышцы спины. Пловцы часто используют это упражнение как силовое, позволяющее им получать хорошие результаты в стиле кроль.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack06.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Спина - Тяги нижнего блока (гребля)', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/tyagi-nizhnego-bloka-greblya', 'Это упражнение превосходно формирует толщину спины, задействуя широчайшую мышцу спины, большую круглую мышцу, задние части дельтовидных мышц.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack07.jpg', 'Спина - Тяги нижнего блока (гребля)', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/tyagi-nizhnego-bloka-greblya', 'Это упражнение превосходно формирует толщину спины, задействуя широчайшую мышцу спины, большую круглую мышцу, задние части дельтовидных мышц.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack07.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Спина - Тяги гантели одной рукой', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/tyagi-ganteli-odnoj-rukoj', 'Это упражнение преимущественно нагружает широчайшие мышцы спины, большую круглую мышцу, заднюю часть дельтовидных мышц, а также трапециевидную и ромбовидную мышцы в конечной фазе движения.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack08.jpg', 'Спина - Тяги гантели одной рукой', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/tyagi-ganteli-odnoj-rukoj', 'Это упражнение преимущественно нагружает широчайшие мышцы спины, большую круглую мышцу, заднюю часть дельтовидных мышц, а также трапециевидную и ромбовидную мышцы в конечной фазе движения.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack08.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Спина - Тяги штанги, стоя в наклоне', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/tyagi-shtangi-stoya-v-naklone', 'Это упражнение задействует широчайшие мышцы спины, большие круглые мышцы, задние части дельтовидных мышц, сгибатели руки, а при сведении лопаток друг с другом - ромбовидные и трапециевидные мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack09.jpg', 'Спина - Тяги штанги, стоя в наклоне', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/tyagi-shtangi-stoya-v-naklone', 'Это упражнение задействует широчайшие мышцы спины, большие круглые мышцы, задние части дельтовидных мышц, сгибатели руки, а при сведении лопаток друг с другом - ромбовидные и трапециевидные мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack09.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Спина - Тяги Т-образного грифа (гребля)', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/tyagi-t-obraznogo-grifa-greblya', 'Это упражнение концентрирует нагрузку на мышцах спины, не требуя значительных усилий для сохранения правильного положения тела.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack10.jpg', 'Спина - Тяги Т-образного грифа (гребля)', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/tyagi-t-obraznogo-grifa-greblya', 'Это упражнение концентрирует нагрузку на мышцах спины, не требуя значительных усилий для сохранения правильного положения тела.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack10.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Спина - Тяги Т-образного грифа (гребля) с упором', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/tyagi-t-obraznogo-grifa-greblya-s-uporom', 'Это упражнение позволяет сделать основной акцент на мышцах спины и требует намного меньше усилий для сохранения правильного положения тела.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack11.jpg', 'Спина - Тяги Т-образного грифа (гребля) с упором', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/tyagi-t-obraznogo-grifa-greblya-s-uporom', 'Это упражнение позволяет сделать основной акцент на мышцах спины и требует намного меньше усилий для сохранения правильного положения тела.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack11.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Спина - Вертикальные тяги', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/vertikalnye-tyagi', 'Это упражнение разрабатывает трапециевидные мышцы, главным образом их верхнюю часть, а также дельтовидные мышцы, мышцы, поднимающие лопатку.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack17.jpg', 'Спина - Вертикальные тяги', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/vertikalnye-tyagi', 'Это упражнение разрабатывает трапециевидные мышцы, главным образом их верхнюю часть, а также дельтовидные мышцы, мышцы, поднимающие лопатку.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack17.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Спина - Шраги со штангой', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/shragi-so-shtangoj', 'Это упражнение развивает верхнюю часть трапециевидной мышцы, главным образом ее затылочно-ключичные пучки, а также лопаточную.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack18.jpg', 'Спина - Шраги со штангой', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/shragi-so-shtangoj', 'Это упражнение развивает верхнюю часть трапециевидной мышцы, главным образом ее затылочно-ключичные пучки, а также лопаточную.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack18.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Спина - Шраги с гантелями', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/shragi-s-gantelyami', 'Это упражнение предназначено для разработки верхних, или ключичных, частей трапециевидных мышц, мышц, поднимающих лопатку, средних частей трапециевидных мышц и ромбовидных мышц, если дополнить поднимание плеч смыканием лопаток.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack19.jpg', 'Спина - Шраги с гантелями', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/shragi-s-gantelyami', 'Это упражнение предназначено для разработки верхних, или ключичных, частей трапециевидных мышц, мышц, поднимающих лопатку, средних частей трапециевидных мышц и ромбовидных мышц, если дополнить поднимание плеч смыканием лопаток.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack19.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Спина - Шраги на тренажере', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/shragi-na-trenazhere', 'Это упражнение при систематическом использовании превосходно подходит для развития верхних частей трапециевидных мышц и мышц, поднимающих лопатки.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack20.jpg', 'Спина - Шраги на тренажере', 'http://bodysportal.com/bodibilding/uprazhneniya/spina/shragi-na-trenazhere', 'Это упражнение при систематическом использовании превосходно подходит для развития верхних частей трапециевидных мышц и мышц, поднимающих лопатки.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack20.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Спина - Становые тяги со штангой', 'http://bodysportal.com/bodibilding/uprazhneniya/poyasnitsa/stanovye-tyagi-so-shtangoj', 'Это упражнение вовлекает в работу ягодичные и четырехглавые мышцы бедра, при этом разрабатывая позвоночно-крестцовые и трапециевидные мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack14.jpg', 'Спина - Становые тяги со штангой', 'http://bodysportal.com/bodibilding/uprazhneniya/poyasnitsa/stanovye-tyagi-so-shtangoj', 'Это упражнение вовлекает в работу ягодичные и четырехглавые мышцы бедра, при этом разрабатывая позвоночно-крестцовые и трапециевидные мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack14.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Спина - Поясничные прогибания', 'http://bodysportal.com/bodibilding/uprazhneniya/poyasnitsa/poyasnichnye-progibaniya', 'Это упражнение развивает главным образом мышцы, разгибающие позвоночник.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack15.jpg', 'Спина - Поясничные прогибания', 'http://bodysportal.com/bodibilding/uprazhneniya/poyasnitsa/poyasnichnye-progibaniya', 'Это упражнение развивает главным образом мышцы, разгибающие позвоночник.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack15.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Спина - Разгибания туловища на тренажере', 'http://bodysportal.com/bodibilding/uprazhneniya/poyasnitsa/razgibaniya-tulovishcha-na-trenazhere', 'Это упражнение разрабатывает мышцы, выпрямляющие позвоночник, локализуя нагрузку в нижней части спины, прежде всего - на крестцово-поясничной группе остистых мышц.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack16.jpg', 'Спина - Разгибания туловища на тренажере', 'http://bodysportal.com/bodibilding/uprazhneniya/poyasnitsa/razgibaniya-tulovishcha-na-trenazhere', 'Это упражнение разрабатывает мышцы, выпрямляющие позвоночник, локализуя нагрузку в нижней части спины, прежде всего - на крестцово-поясничной группе остистых мышц.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack16.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Спина - Подъемы с добрым утром сидя', 'http://bodysportal.com/bodibilding/uprazhneniya/poyasnitsa/pod-emy-s-dobrym-utrom-sidya', 'Это упражнения отлично подойдет для изолированной проработки мышц поясницы и глубоких мышц спины. В отличие, от выполнения подъемов стоя, данный способ исключает нагрузку на ноги и ягодицы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesLowerBack/S_G_Mornings_Mini.jpg', 'Спина - Подъемы с добрым утром сидя', 'http://bodysportal.com/bodibilding/uprazhneniya/poyasnitsa/pod-emy-s-dobrym-utrom-sidya', 'Это упражнения отлично подойдет для изолированной проработки мышц поясницы и глубоких мышц спины. В отличие, от выполнения подъемов стоя, данный способ исключает нагрузку на ноги и ягодицы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesLowerBack/S_G_Mornings_Mini.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Спина - Разгибания туловища на тренажере', 'http://bodysportal.com/bodibilding/uprazhneniya/poyasnitsa/razgibaniya-tulovishcha-na-trenazhere', 'Это упражнение разрабатывает мышцы, выпрямляющие позвоночник, локализуя нагрузку в нижней части спины, прежде всего - на крестцово-поясничной группе остистых мышц.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack16.jpg', 'Спина - Разгибания туловища на тренажере', 'http://bodysportal.com/bodibilding/uprazhneniya/poyasnitsa/razgibaniya-tulovishcha-na-trenazhere', 'Это упражнение разрабатывает мышцы, выпрямляющие позвоночник, локализуя нагрузку в нижней части спины, прежде всего - на крестцово-поясничной группе остистых мышц.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesBack/miniBack16.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Спина - Мертвые тяги в стиле сумо', 'http://bodysportal.com/bodibilding/uprazhneniya/poyasnitsa/mertvye-tyagi-v-stile-sumo', 'В отличие от обычного классического подъема штанги от пола, в этом упражнении более интенсивно работают четырехглавая мышца бедра и приводящая мышца бедра и в меньшей степени - мышцы спины.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet08_from_back13.jpg', 'Спина - Мертвые тяги в стиле сумо', 'http://bodysportal.com/bodibilding/uprazhneniya/poyasnitsa/mertvye-tyagi-v-stile-sumo', 'В отличие от обычного классического подъема штанги от пола, в этом упражнении более интенсивно работают четырехглавая мышца бедра и приводящая мышца бедра и в меньшей степени - мышцы спины.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet08_from_back13.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Спина - Подъемы торса с добрым утром', 'http://bodysportal.com/bodibilding/uprazhneniya/poyasnitsa/pod-emy-torsa-s-dobrym-utrom', 'Это упражнение, разрабатывающее большую ягодичную мышцу и мышцы поясницы, оказывает благоприятное воздействие на седалищно-подколенные мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet11.jpg', 'Спина - Подъемы торса с добрым утром', 'http://bodysportal.com/bodibilding/uprazhneniya/poyasnitsa/pod-emy-torsa-s-dobrym-utrom', 'Это упражнение, разрабатывающее большую ягодичную мышцу и мышцы поясницы, оказывает благоприятное воздействие на седалищно-подколенные мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet11.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Спина - Мертвые тяги со штангой, ноги прямые', 'http://bodysportal.com/bodibilding/uprazhneniya/poyasnitsa/mertvye-tyagi-so-shtangoj-nogi-pryamye', 'Движения упражнения активно включают в работу большую ягодичную и седалищно-большеберцовую мышцу. Также хорошо задействованы мышцы, выпрямляющие позвоночник.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet011_from_back12.jpg', 'Спина - Мертвые тяги со штангой, ноги прямые', 'http://bodysportal.com/bodibilding/uprazhneniya/poyasnitsa/mertvye-tyagi-so-shtangoj-nogi-pryamye', 'Движения упражнения активно включают в работу большую ягодичную и седалищно-большеберцовую мышцу. Также хорошо задействованы мышцы, выпрямляющие позвоночник.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet011_from_back12.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Грудь - Жим штанги, лежа на наклонной скамье', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/zhim-shtangi-lezha-na-naklonnoj-skame', 'Это упражнение задействует ключичный отдел большой грудной мышцы, передние части дельтовидных мышц; трицепсы, переднюю зубчатую и малую грудную мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesChest/miniChest01.jpg', 'Грудь - Жим штанги, лежа на наклонной скамье', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/zhim-shtangi-lezha-na-naklonnoj-skame', 'Это упражнение задействует ключичный отдел большой грудной мышцы, передние части дельтовидных мышц; трицепсы, переднюю зубчатую и малую грудную мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesChest/miniChest01.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Грудь - Жим гантелей, лежа на наклонной скамье', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/zhim-gantelej-lezha-na-naklonnoj-skame', 'Это упражнение является как бы промежуточным упражнением между жимом штанги, лежа на наклонной скамье, и разведением гантелей на наклонной скамье и задействует прежде всего ключичные части грудных мышц.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesChest/miniChest09.jpg', 'Грудь - Жим гантелей, лежа на наклонной скамье', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/zhim-gantelej-lezha-na-naklonnoj-skame', 'Это упражнение является как бы промежуточным упражнением между жимом штанги, лежа на наклонной скамье, и разведением гантелей на наклонной скамье и задействует прежде всего ключичные части грудных мышц.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesChest/miniChest09.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Грудь - Разведение гантелей, лежа на наклонной скамье', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/razvedenie-gantelej-lezha-na-naklonnoj-skame', 'Это упражнение локализует усилие главным образом на верхние части большой грудной мышцы. Наряду с протяжкой гантели или штанги (pull-over) это упражнение является базовым для увеличения грудной клетки.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesChest/miniChest10.jpg', 'Грудь - Разведение гантелей, лежа на наклонной скамье', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/razvedenie-gantelej-lezha-na-naklonnoj-skame', 'Это упражнение локализует усилие главным образом на верхние части большой грудной мышцы. Наряду с протяжкой гантели или штанги (pull-over) это упражнение является базовым для увеличения грудной клетки.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesChest/miniChest10.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Грудь - Жим штанги, лежа на горизонтальной скамье', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/zhim-shtangi-lezha-na-gorizontalnoj-skame', 'Это упражнение развивает всю большую грудную мышцу, малую грудную мышцу, трицепсы, переднюю часть дельтовидной мышцы, зубчатые и клювовидно-плечевые мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesChest/miniChest02.jpg', 'Грудь - Жим штанги, лежа на горизонтальной скамье', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/zhim-shtangi-lezha-na-gorizontalnoj-skame', 'Это упражнение развивает всю большую грудную мышцу, малую грудную мышцу, трицепсы, переднюю часть дельтовидной мышцы, зубчатые и клювовидно-плечевые мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesChest/miniChest02.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Грудь - Отжимания от пола', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/otzhimaniya-ot-pola', 'В положении лицом вниз, упираясь прямыми руками в пол, ладони на ширине плеч или чуть шире. Ноги вместе или слегка расставлены.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesChest/miniChest05.jpg', 'Грудь - Отжимания от пола', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/otzhimaniya-ot-pola', 'В положении лицом вниз, упираясь прямыми руками в пол, ладони на ширине плеч или чуть шире. Ноги вместе или слегка расставлены.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesChest/miniChest05.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Грудь - Жим гантелей лежа', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/zhim-gantelej-lezha', 'Это упражнение аналогично жиму штанги лежа, за исключением того, что упражнение с гантелями характеризуется большей амплитудой, способствующей лучшему растягиванию больших грудных мышц.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesChest/miniChest07.jpg', 'Грудь - Жим гантелей лежа', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/zhim-gantelej-lezha', 'Это упражнение аналогично жиму штанги лежа, за исключением того, что упражнение с гантелями характеризуется большей амплитудой, способствующей лучшему растягиванию больших грудных мышц.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesChest/miniChest07.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Грудь - Разведение гантелей лежа', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/razvedenie-gantelej-lezha', 'Это базовое упражнение для увеличения объема груди и способствует увеличению объема легких. Кроме того, оно придает эластичность мышцам.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesChest/miniChest08.jpg', 'Грудь - Разведение гантелей лежа', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/razvedenie-gantelej-lezha', 'Это базовое упражнение для увеличения объема груди и способствует увеличению объема легких. Кроме того, оно придает эластичность мышцам.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesChest/miniChest08.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Грудь - Тяга штанги лежа PULL-OVER', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/tyaga-shtangi-lezha-pull-over', 'Упражнение великолепно расширяет грудную клетку. Выполняя его, используйте нагрузки с легким весом и следите за положением туловища и правильным дыханием.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesChest/miniChest14.jpg', 'Грудь - Тяга штанги лежа PULL-OVER', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/tyaga-shtangi-lezha-pull-over', 'Упражнение великолепно расширяет грудную клетку. Выполняя его, используйте нагрузки с легким весом и следите за положением туловища и правильным дыханием.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesChest/miniChest14.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Грудь - Жим штанги, лежа на скамье с уклоном', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/zhim-shtangi-lezha-na-skame-s-uklonom', 'Это упражнение формирует нижний подрез грудных мышц. Кроме того, при опускании грифа штанги к шее растягивается большая грудная мышца, что способствует увеличению ее эластичности.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesChest/miniChest04.jpg', 'Грудь - Жим штанги, лежа на скамье с уклоном', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/zhim-shtangi-lezha-na-skame-s-uklonom', 'Это упражнение формирует нижний подрез грудных мышц. Кроме того, при опускании грифа штанги к шее растягивается большая грудная мышца, что способствует увеличению ее эластичности.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesChest/miniChest04.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Грудь - Отжимания на брусьях', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/otzhimaniya-na-brusyakh', 'Это упражнение прекрасно растягивает большие грудные мышцы и повышает эластичность мышц плечевого пояса.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesChest/miniChest06.jpg', 'Грудь - Отжимания на брусьях', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/otzhimaniya-na-brusyakh', 'Это упражнение прекрасно растягивает большие грудные мышцы и повышает эластичность мышц плечевого пояса.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesChest/miniChest06.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Грудь - Жим штанги узким хватом, лежа на скамье', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/zhim-shtangi-uzkim-khvatom-lezha-na-skame', 'Это упражнение великолепно подходит для развития внутренней прорисовки грудной мышцы и трицепсов.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesChest/miniChest03.jpg', 'Грудь - Жим штанги узким хватом, лежа на скамье', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/zhim-shtangi-uzkim-khvatom-lezha-na-skame', 'Это упражнение великолепно подходит для развития внутренней прорисовки грудной мышцы и трицепсов.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesChest/miniChest03.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Грудь - Сведение рук на тренажере', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/svedenie-ruk-na-trenazhere', 'Это упражнение разрабатывает большие грудные мышцы. Во время сведения локтей оно локализует усилие на уровне внутренней части мышц груди, также разрабатывая клювовидно-плечевые мышцы и короткую головку бицепсов.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesChest/miniChest11.jpg', 'Грудь - Сведение рук на тренажере', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/svedenie-ruk-na-trenazhere', 'Это упражнение разрабатывает большие грудные мышцы. Во время сведения локтей оно локализует усилие на уровне внутренней части мышц груди, также разрабатывая клювовидно-плечевые мышцы и короткую головку бицепсов.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesChest/miniChest11.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Грудь - Сведение верхних блоков CROSS-OVER', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/svedenie-verkhnikh-blokov-cross-over', 'Это упражнение превосходно развивает большую грудную мышцу. Меняя угол наклона туловища и траекторию движения рук, то есть, сближая руки на различном по высоте уровне можно задействовать все части большой грудной мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesChest/miniChest12.jpg', 'Грудь - Сведение верхних блоков CROSS-OVER', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/svedenie-verkhnikh-blokov-cross-over', 'Это упражнение превосходно развивает большую грудную мышцу. Меняя угол наклона туловища и траекторию движения рук, то есть, сближая руки на различном по высоте уровне можно задействовать все части большой грудной мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesChest/miniChest12.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Грудь - Тяга гантели из-за головы лежа PULL-OVER', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/tyaga-ganteli-iz-za-golovy-lezha-pull-over', 'Это упражнение развивает внутреннюю часть большой грудной мышцы, длинную головку трицепсов, большую круглую мышцу, широчайшую мышцу спины, а также переднюю зубчатую, ромбовидную и малую грудную мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesChest/miniChest13.jpg', 'Грудь - Тяга гантели из-за головы лежа PULL-OVER', 'http://bodysportal.com/bodibilding/uprazhneniya/grudnye-myshtsy/tyaga-ganteli-iz-za-golovy-lezha-pull-over', 'Это упражнение развивает внутреннюю часть большой грудной мышцы, длинную головку трицепсов, большую круглую мышцу, широчайшую мышцу спины, а также переднюю зубчатую, ромбовидную и малую грудную мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesChest/miniChest13.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Бицепс - Попеременные сгибания рук с гантелями', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/poperemennye-sgibaniya-ruk-s-gantelyami', 'В упражнении участвуют мышцы: плечелучевая, плечевая, двуглавая (бицепс), передняя дельтовидная, в меньшей степени клювовидно-плечевая и верхний отдел большой грудной мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/01_miniBiceps.jpg', 'Бицепс - Попеременные сгибания рук с гантелями', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/poperemennye-sgibaniya-ruk-s-gantelyami', 'В упражнении участвуют мышцы: плечелучевая, плечевая, двуглавая (бицепс), передняя дельтовидная, в меньшей степени клювовидно-плечевая и верхний отдел большой грудной мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/01_miniBiceps.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Бицепс - Концентрированное сгибание одной руки с гантелью', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/kontsentrirovannoe-sgibanie-odnoj-ruki-s-gantelyu', 'Это упражнение позволит вам контролировать амплитуду, скорость и размерность движений. Оно предназначено главным образом для работы бицепсов и плечевых мышц.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/02_miniBiceps.jpg', 'Бицепс - Концентрированное сгибание одной руки с гантелью', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/kontsentrirovannoe-sgibanie-odnoj-ruki-s-gantelyu', 'Это упражнение позволит вам контролировать амплитуду, скорость и размерность движений. Оно предназначено главным образом для работы бицепсов и плечевых мышц.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/02_miniBiceps.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Бицепс - Сгибание рук с гантелями хватом молоток', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/sgibanie-ruk-s-gantelyami-khvatom-molotok', 'Это лучшее упражнение для плечелучевых мышц. В нем также участвуют бицепс и частично плечевая мышца и в меньшей степени короткий и длинный лучевые разгибатели запястья.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/03_miniBiceps.jpg', 'Бицепс - Сгибание рук с гантелями хватом молоток', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/sgibanie-ruk-s-gantelyami-khvatom-molotok', 'Это лучшее упражнение для плечелучевых мышц. В нем также участвуют бицепс и частично плечевая мышца и в меньшей степени короткий и длинный лучевые разгибатели запястья.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/03_miniBiceps.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Бицепс - Сгибание одной руки с рукояткой нижнего блока', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/sgibanie-odnoj-ruki-s-rukoyatkoj-nizhnego-bloka', 'Это хорошее упражнение для изолированной накачки бицепсов.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/04_miniBiceps.jpg', 'Бицепс - Сгибание одной руки с рукояткой нижнего блока', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/sgibanie-odnoj-ruki-s-rukoyatkoj-nizhnego-bloka', 'Это хорошее упражнение для изолированной накачки бицепсов.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/04_miniBiceps.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Бицепс - Сгибание рук с рукоятками верхних блоков', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/sgibanie-ruk-s-rukoyatkami-verkhnikh-blokov', 'Это упражнение используют для завершения тренировки по развитию бицепсов. Оно в основном задействует короткую головку, хорошо ее сокращая и растягивая. Это упражнение также тренирует плечевые мышцы и моносуставной разгибатель локтя.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/05_miniBiceps.jpg', 'Бицепс - Сгибание рук с рукоятками верхних блоков', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/sgibanie-ruk-s-rukoyatkami-verkhnikh-blokov', 'Это упражнение используют для завершения тренировки по развитию бицепсов. Оно в основном задействует короткую головку, хорошо ее сокращая и растягивая. Это упражнение также тренирует плечевые мышцы и моносуставной разгибатель локтя.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/05_miniBiceps.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Бицепс - Сгибание рук с грифом штанги', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/sgibanie-ruk-s-grifom-shtangi', 'Это упражнение задействует бицепсы, плечевые мышцы и в меньшей степени плечелучевые мышцы, круглые пронаторы, все сгибатели кисти и пальцев. Во избежание отклонения туловища напрягите мышцы ягодиц, живота и спины.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/06_miniBiceps.jpg', 'Бицепс - Сгибание рук с грифом штанги', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/sgibanie-ruk-s-grifom-shtangi', 'Это упражнение задействует бицепсы, плечевые мышцы и в меньшей степени плечелучевые мышцы, круглые пронаторы, все сгибатели кисти и пальцев. Во избежание отклонения туловища напрягите мышцы ягодиц, живота и спины.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/06_miniBiceps.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Бицепс - Сгибание рук на тренажере LARRY-SCOTT', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/sgibanie-ruk-na-trenazhere-larry-scott', 'Это одно из лучших упражнений для изолированной проработки бицепсов. Оно тренирует также плечевые мышцы и в меньшей степени плечелучевые мышцы и круглые пронаторы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/07_miniBiceps.jpg', 'Бицепс - Сгибание рук на тренажере LARRY-SCOTT', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/sgibanie-ruk-na-trenazhere-larry-scott', 'Это одно из лучших упражнений для изолированной проработки бицепсов. Оно тренирует также плечевые мышцы и в меньшей степени плечелучевые мышцы и круглые пронаторы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/07_miniBiceps.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Бицепс - Сгибание рук на скамье LARRY-SCOTT', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/sgibanie-ruk-na-skame-larry-scott', 'Это одно из лучших упражнений для локального воздействия на бицепсы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/08_miniBiceps.jpg', 'Бицепс - Сгибание рук на скамье LARRY-SCOTT', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/sgibanie-ruk-na-skame-larry-scott', 'Это одно из лучших упражнений для локального воздействия на бицепсы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/08_miniBiceps.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Предплечья - Сгибание рук со штангой хватом сверху', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/sgibanie-ruk-so-shtangoj-khvatom-sverkhu', 'Это упражнение прорабатывает мышцы - разгибатели запястья; длинный лучевой разгибатель запястья, короткий лучевой разгибатель запястья, разгибатель пальцев, разгибатель мизинца и локтевой разгибатель запястья.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/09_miniForearms.jpg', 'Предплечья - Сгибание рук со штангой хватом сверху', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/sgibanie-ruk-so-shtangoj-khvatom-sverkhu', 'Это упражнение прорабатывает мышцы - разгибатели запястья; длинный лучевой разгибатель запястья, короткий лучевой разгибатель запястья, разгибатель пальцев, разгибатель мизинца и локтевой разгибатель запястья.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/09_miniForearms.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Предплечья - Разгибание запястий со штангой хватом сверху', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/razgibanie-zapyastij-so-shtangoj-khvatom-sverkhu', 'Это упражнение укрепляет суставы запястья, которые часто бывают слабыми из-за недостаточной силы мышц разгибателей кисти.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/10_miniForearms.jpg', 'Предплечья - Разгибание запястий со штангой хватом сверху', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/razgibanie-zapyastij-so-shtangoj-khvatom-sverkhu', 'Это упражнение укрепляет суставы запястья, которые часто бывают слабыми из-за недостаточной силы мышц разгибателей кисти.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/10_miniForearms.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Предплечья - Сгибание запястий со штангой хватом снизу', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/sgibanie-zapyastij-so-shtangoj-khvatom-snizu', 'Это упражнение тренирует лучевой сгибатель запястья, длинную ладонную мышцу, локтевой сгибатель запястья, а также глубокие и поверхностные сгибатели пальцев, которые, несмотря на то, что расположены глубоко, обычно составляют основную часть от общего объема работы сгибателей запястья.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/11_miniForearms.jpg', 'Предплечья - Сгибание запястий со штангой хватом снизу', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/sgibanie-zapyastij-so-shtangoj-khvatom-snizu', 'Это упражнение тренирует лучевой сгибатель запястья, длинную ладонную мышцу, локтевой сгибатель запястья, а также глубокие и поверхностные сгибатели пальцев, которые, несмотря на то, что расположены глубоко, обычно составляют основную часть от общего объема работы сгибателей запястья.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/11_miniForearms.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Трицепс - Разгибание рук с рукояткой верхнего блока хватом сверху', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/razgibanie-ruk-s-rukoyatkoj-verkhnego-bloka-khvatom-sverkhu', 'Это упражнение изолированно тренирует трицепсы и локтевые мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/12_miniTriceps.jpg', 'Трицепс - Разгибание рук с рукояткой верхнего блока хватом сверху', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/razgibanie-ruk-s-rukoyatkoj-verkhnego-bloka-khvatom-sverkhu', 'Это упражнение изолированно тренирует трицепсы и локтевые мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/12_miniTriceps.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Трицепс - Разгибание рук с рукояткой верхнего блока хватом снизу', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/razgibanie-ruk-s-rukoyatkoj-verkhnego-bloka-khvatom-snizu', 'Во время разгибания рук работают локтевые мышцы и разгибатели запястья. Разгибатели кистей и пальцев стабилизируют кисти при выполнении изометрического напряжения во время упражнения.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/13_miniTriceps.jpg', 'Трицепс - Разгибание рук с рукояткой верхнего блока хватом снизу', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/razgibanie-ruk-s-rukoyatkoj-verkhnego-bloka-khvatom-snizu', 'Во время разгибания рук работают локтевые мышцы и разгибатели запястья. Разгибатели кистей и пальцев стабилизируют кисти при выполнении изометрического напряжения во время упражнения.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/13_miniTriceps.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Трицепс - Разгибание одной руки с верхним блоком хватом снизу', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/razgibanie-odnoj-ruki-s-verkhnim-blokom-khvatom-snizu', 'Это упражнение прорабатывает преимущественно латеральную головку трицепса.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/14_miniTriceps.jpg', 'Трицепс - Разгибание одной руки с верхним блоком хватом снизу', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/razgibanie-odnoj-ruki-s-verkhnim-blokom-khvatom-snizu', 'Это упражнение прорабатывает преимущественно латеральную головку трицепса.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/14_miniTriceps.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Трицепс - Разгибание рук со штангой лежа (французский жим)', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/razgibanie-ruk-so-shtangoj-lezha', 'Лежа на горизонтальной скамье. Гриф штанги взять хватом сверху на прямых, вертикально поднятых руках...', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/15_miniTriceps.jpg', 'Трицепс - Разгибание рук со штангой лежа (французский жим)', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/razgibanie-ruk-so-shtangoj-lezha', 'Лежа на горизонтальной скамье. Гриф штанги взять хватом сверху на прямых, вертикально поднятых руках...', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/15_miniTriceps.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Трицепс - Разгибание рук с гантелями лежа', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/razgibanie-ruk-s-gantelyami-lezha', 'Это упражнение позволяет контролировать работу и равномерно распределять нагрузку на все три головки трицепса.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/16_miniTriceps.jpg', 'Трицепс - Разгибание рук с гантелями лежа', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/razgibanie-ruk-s-gantelyami-lezha', 'Это упражнение позволяет контролировать работу и равномерно распределять нагрузку на все три головки трицепса.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/16_miniTriceps.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Трицепс - Разгибание одной руки с гантелью из-за головы', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/razgibanie-odnoj-ruki-s-gantelyu-iz-za-golovy', 'В процессе движения особое внимание обратите на сокращение длинной головки трицепса, которая сокращается, напрягаясь в разогнутом вертикальном положении руки.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/17_miniTriceps.jpg', 'Трицепс - Разгибание одной руки с гантелью из-за головы', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/razgibanie-odnoj-ruki-s-gantelyu-iz-za-golovy', 'В процессе движения особое внимание обратите на сокращение длинной головки трицепса, которая сокращается, напрягаясь в разогнутом вертикальном положении руки.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/17_miniTriceps.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Трицепс - Разгибание рук с одной гантелью из-за головы', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/razgibanie-ruk-s-odnoj-gantelyu-iz-za-golovy', 'Вертикальное положение рук способствует максимальному напряжению длинной головки трицепса.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/18_miniTriceps.jpg', 'Трицепс - Разгибание рук с одной гантелью из-за головы', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/razgibanie-ruk-s-odnoj-gantelyu-iz-za-golovy', 'Вертикальное положение рук способствует максимальному напряжению длинной головки трицепса.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/18_miniTriceps.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Трицепс - Разгибание рук с изогнутым грифом штанги из-за головы', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/razgibanie-ruk-s-izognutym-grifom-shtangi-iz-za-golovy', 'Вертикальное положение рук способствует наибольшему сокращению длинной головки трицепса, позволяя максимально включать ее в работу. Хват сверху помогает проработать латеральную головку трицепсов.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/19_miniTriceps.jpg', 'Трицепс - Разгибание рук с изогнутым грифом штанги из-за головы', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/razgibanie-ruk-s-izognutym-grifom-shtangi-iz-za-golovy', 'Вертикальное положение рук способствует наибольшему сокращению длинной головки трицепса, позволяя максимально включать ее в работу. Хват сверху помогает проработать латеральную головку трицепсов.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/19_miniTriceps.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Трицепс - Разгибание одной руки назад с гантелью в наклоне', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/razgibanie-odnoj-ruki-nazad-s-gantelyu-v-naklone', 'Это упражнение великолепно подходит для доработки трицепсов.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/20_miniTriceps.jpg', 'Трицепс - Разгибание одной руки назад с гантелью в наклоне', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/razgibanie-odnoj-ruki-nazad-s-gantelyu-v-naklone', 'Это упражнение великолепно подходит для доработки трицепсов.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/20_miniTriceps.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Трицепс - Отжимание трицепсами спиной к скамье', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/otzhimanie-tritsepsami-spinoj-k-skame', 'Это упражнение прорабатывает трицепсы, грудные мышцы и передние отделы дельтовидных мышц. Чтобы дополнительно усилить нагрузку, положите на переднюю поверхность бедер отягощения.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/21_miniTriceps.jpg', 'Трицепс - Отжимание трицепсами спиной к скамье', 'http://bodysportal.com/bodibilding/uprazhneniya/ruki/otzhimanie-tritsepsami-spinoj-k-skame', 'Это упражнение прорабатывает трицепсы, грудные мышцы и передние отделы дельтовидных мышц. Чтобы дополнительно усилить нагрузку, положите на переднюю поверхность бедер отягощения.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesHands/21_miniTriceps.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Пресс - Сворачивание туловища с верхним блоком', 'http://bodysportal.com/bodibilding/uprazhneniya/zhivot/svorachivanie-tulovishcha-s-verkhnim-blokom', 'Отличное упражнение для проработки прямых мышц живота. В зависимости от положения туловища можно делать акцент, как на верхние, так и на нижние участки пресса.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesStomach/Stomach-mini-07.jpg', 'Пресс - Сворачивание туловища с верхним блоком', 'http://bodysportal.com/bodibilding/uprazhneniya/zhivot/svorachivanie-tulovishcha-s-verkhnim-blokom', 'Отличное упражнение для проработки прямых мышц живота. В зависимости от положения туловища можно делать акцент, как на верхние, так и на нижние участки пресса.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesStomach/Stomach-mini-07.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Пресс - Сворачивание туловища на тренажере', 'http://bodysportal.com/bodibilding/uprazhneniya/zhivot/svorachivanie-tulovishcha-na-trenazhere', 'Это упражнение позволяет удобно подбирать и регулировать необходимый вес для выполнения. Рекомендуется начинающим спортсменам.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesStomach/Stomach-mini-8.jpg', 'Пресс - Сворачивание туловища на тренажере', 'http://bodysportal.com/bodibilding/uprazhneniya/zhivot/svorachivanie-tulovishcha-na-trenazhere', 'Это упражнение позволяет удобно подбирать и регулировать необходимый вес для выполнения. Рекомендуется начинающим спортсменам.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesStomach/Stomach-mini-8.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Пресс - Сворачивание туловища на полу', 'http://bodysportal.com/bodibilding/uprazhneniya/zhivot/svorachivanie-tulovishcha-na-polu', 'Это отличное упражнение для пресса, оно в основном нагружает прямые мышцы живота.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesStomach/Stomach-mini-01.jpg', 'Пресс - Сворачивание туловища на полу', 'http://bodysportal.com/bodibilding/uprazhneniya/zhivot/svorachivanie-tulovishcha-na-polu', 'Это отличное упражнение для пресса, оно в основном нагружает прямые мышцы живота.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesStomach/Stomach-mini-01.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Пресс - Подъемы туловища на вертикальной скамье', 'http://bodysportal.com/bodibilding/uprazhneniya/zhivot/pod-emy-tulovishcha-na-vertikalnoj-skame', 'Это прекрасное упражнение для разработки прямых мышц пресса живота. Оно также задействует, но менее интенсивно, косые мышцы живота.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesStomach/Stomach-mini-06.jpg', 'Пресс - Подъемы туловища на вертикальной скамье', 'http://bodysportal.com/bodibilding/uprazhneniya/zhivot/pod-emy-tulovishcha-na-vertikalnoj-skame', 'Это прекрасное упражнение для разработки прямых мышц пресса живота. Оно также задействует, но менее интенсивно, косые мышцы живота.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesStomach/Stomach-mini-06.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Пресс - Подъемы туловища на наклонной скамье', 'http://bodysportal.com/bodibilding/uprazhneniya/zhivot/pod-emy-tulovishcha-na-naklonnoj-skame', 'Это упражнение следует выполнять с многократными повторениями. Оно позволяет разрабатывать все мышцы живота.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesStomach/Stomach-mini-05.jpg', 'Пресс - Подъемы туловища на наклонной скамье', 'http://bodysportal.com/bodibilding/uprazhneniya/zhivot/pod-emy-tulovishcha-na-naklonnoj-skame', 'Это упражнение следует выполнять с многократными повторениями. Оно позволяет разрабатывать все мышцы живота.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesStomach/Stomach-mini-05.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Пресс - Сворачивание туловища с голенью на скамье', 'http://bodysportal.com/bodibilding/uprazhneniya/zhivot/svorachivanie-tulovishcha-s-golenyu-na-skame', 'Это упражнение концентрирует усилия на прямых мышцах живота, особенно на их верхних частях.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesStomach/Stomach-mini-04.jpg', 'Пресс - Сворачивание туловища с голенью на скамье', 'http://bodysportal.com/bodibilding/uprazhneniya/zhivot/svorachivanie-tulovishcha-s-golenyu-na-skame', 'Это упражнение концентрирует усилия на прямых мышцах живота, особенно на их верхних частях.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesStomach/Stomach-mini-04.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Пресс - Подъемы туловища', 'http://bodysportal.com/bodibilding/uprazhneniya/zhivot/pod-emy-tulovishcha', 'Это упражнение задействует сгибатели бедра, а также косые мышцы живота, однако главным образом оно разрабатывает прямые мышцы живота.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesStomach/Stomach-mini-02.jpg', 'Пресс - Подъемы туловища', 'http://bodysportal.com/bodibilding/uprazhneniya/zhivot/pod-emy-tulovishcha', 'Это упражнение задействует сгибатели бедра, а также косые мышцы живота, однако главным образом оно разрабатывает прямые мышцы живота.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesStomach/Stomach-mini-02.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Пресс - Подъемы туловища у гимнастической стенки', 'http://bodysportal.com/bodibilding/uprazhneniya/zhivot/pod-emy-tulovishcha-u-gimnasticheskoj-stenki', 'Отличное упражнение для прокачки пресса живота. Оно разрабатывает прямые мышцы живота и в меньшей степени внутренние и наружные косые мышцы живота.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesStomach/Stomach-mini-03.jpg', 'Пресс - Подъемы туловища у гимнастической стенки', 'http://bodysportal.com/bodibilding/uprazhneniya/zhivot/pod-emy-tulovishcha-u-gimnasticheskoj-stenki', 'Отличное упражнение для прокачки пресса живота. Оно разрабатывает прямые мышцы живота и в меньшей степени внутренние и наружные косые мышцы живота.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesStomach/Stomach-mini-03.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Пресс - Подъемы ног на наклонной скамье', 'http://bodysportal.com/bodibilding/uprazhneniya/zhivot/pod-emy-nog-na-naklonnoj-skame', 'Это упражнение задействует прямые мышцы пресса и меньшей степени косые мышцы живота.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesStomach/Stomach-mini-9.jpg', 'Пресс - Подъемы ног на наклонной скамье', 'http://bodysportal.com/bodibilding/uprazhneniya/zhivot/pod-emy-nog-na-naklonnoj-skame', 'Это упражнение задействует прямые мышцы пресса и меньшей степени косые мышцы живота.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesStomach/Stomach-mini-9.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Пресс - Подъемы коленей в упоре', 'http://bodysportal.com/bodibilding/uprazhneniya/zhivot/pod-emy-kolenej-v-upore', 'Это упражнение разрабатывает мышцы - сгибатели бедер, в первую очередь подвздошно-поясничные, а также косые и прямые мышцы живота (особенно интенсивно задействованы их нижние части).', 'http://bodysportal.com/images/bodibilding/exercises/exercisesStomach/Stomach-mini-10.jpg', 'Пресс - Подъемы коленей в упоре', 'http://bodysportal.com/bodibilding/uprazhneniya/zhivot/pod-emy-kolenej-v-upore', 'Это упражнение разрабатывает мышцы - сгибатели бедер, в первую очередь подвздошно-поясничные, а также косые и прямые мышцы живота (особенно интенсивно задействованы их нижние части).', 'http://bodysportal.com/images/bodibilding/exercises/exercisesStomach/Stomach-mini-10.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Пресс - Подъемы коленей в висе', 'http://bodysportal.com/bodibilding/uprazhneniya/zhivot/pod-emy-kolenej-v-vise', 'Упражнение прорабатывает как пресс живота, так и мышцы спины. Для более изолированной работы мышц живота не опускайте колени ниже горизонтального положения.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesStomach/Stomach-mini-11.jpg', 'Пресс - Подъемы коленей в висе', 'http://bodysportal.com/bodibilding/uprazhneniya/zhivot/pod-emy-kolenej-v-vise', 'Упражнение прорабатывает как пресс живота, так и мышцы спины. Для более изолированной работы мышц живота не опускайте колени ниже горизонтального положения.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesStomach/Stomach-mini-11.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Пресс - Развороты туловища с грифом', 'http://bodysportal.com/bodibilding/uprazhneniya/zhivot/razvoroty-tulovishcha-s-grifom', 'Это отличное упражнение для проработки внутренних и наружных косых мышц живота.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesStomach/Stomach-mini-12.jpg', 'Пресс - Развороты туловища с грифом', 'http://bodysportal.com/bodibilding/uprazhneniya/zhivot/razvoroty-tulovishcha-s-grifom', 'Это отличное упражнение для проработки внутренних и наружных косых мышц живота.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesStomach/Stomach-mini-12.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Пресс - Боковые наклоны стоя', 'http://bodysportal.com/bodibilding/uprazhneniya/zhivot/bokovye-naklony-stoya', 'Это упражнение концентрирует нагрузку на косых мышцах живота, особенно на той стороне, которая сгибается, а также в меньшей мере вовлекает в работу прямые мышцы живота.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesStomach/Stomach-mini-13.jpg', 'Пресс - Боковые наклоны стоя', 'http://bodysportal.com/bodibilding/uprazhneniya/zhivot/bokovye-naklony-stoya', 'Это упражнение концентрирует нагрузку на косых мышцах живота, особенно на той стороне, которая сгибается, а также в меньшей мере вовлекает в работу прямые мышцы живота.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesStomach/Stomach-mini-13.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Пресс - Боковые подъемы туловища на римском стуле', 'http://bodysportal.com/bodibilding/uprazhneniya/zhivot/bokovye-pod-emy-tulovishcha-na-rimskom-stule', 'Основная нагрузка ложится на косую и прямую мышцы живота на той стороне, в которую осуществляется сгибание.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesStomach/Stomach-mini-14.jpg', 'Пресс - Боковые подъемы туловища на римском стуле', 'http://bodysportal.com/bodibilding/uprazhneniya/zhivot/bokovye-pod-emy-tulovishcha-na-rimskom-stule', 'Основная нагрузка ложится на косую и прямую мышцы живота на той стороне, в которую осуществляется сгибание.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesStomach/Stomach-mini-14.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Пресс - Вращения туловища стоя на тренажере Твист', 'http://bodysportal.com/bodibilding/uprazhneniya/zhivot/vrashchenie-tulovishcha-stoya-na-trenazhere-tvist', 'Это упражнение задействует в первую очередь наружные и внутренние косые мышцы живота, вовлекая в работу также прямые мышцы живота.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesStomach/Stomach-mini-15.jpg', 'Пресс - Вращения туловища стоя на тренажере Твист', 'http://bodysportal.com/bodibilding/uprazhneniya/zhivot/vrashchenie-tulovishcha-stoya-na-trenazhere-tvist', 'Это упражнение задействует в первую очередь наружные и внутренние косые мышцы живота, вовлекая в работу также прямые мышцы живота.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesStomach/Stomach-mini-15.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Ноги - Приседания с гантелями', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/prisedaniya-s-gantelyami', 'Это упражнение задействует в первую очередь четырехглавые мышцы бедер и ягодичные мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet01.jpg', 'Ноги - Приседания с гантелями', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/prisedaniya-s-gantelyami', 'Это упражнение задействует в первую очередь четырехглавые мышцы бедер и ягодичные мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet01.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Ноги - Приседания со штангой на груди', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/prisedaniya-so-shtangoj-na-grudi', 'Этот прием во время приседаний локализует больше нагрузки на четырехглавые мышцы, чем при классических приседаниях. Совершая полную амплитуду, вы вовлекаете в работу ягодичные мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet02.jpg', 'Ноги - Приседания со штангой на груди', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/prisedaniya-so-shtangoj-na-grudi', 'Этот прием во время приседаний локализует больше нагрузки на четырехглавые мышцы, чем при классических приседаниях. Совершая полную амплитуду, вы вовлекаете в работу ягодичные мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet02.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Ноги - Приседания со штангой на плечах', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/prisedaniya-so-shtangoj-na-plechakh', 'Приседания разрабатывают главным образом четырехглавые мышцы, ягодичные мышцы, все приводящие мышцы, мышцы, выпрямляющие позвоночник, мышцы живота, а также седалищно-большеберцовые мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet03.jpg', 'Ноги - Приседания со штангой на плечах', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/prisedaniya-so-shtangoj-na-plechakh', 'Приседания разрабатывают главным образом четырехглавые мышцы, ягодичные мышцы, все приводящие мышцы, мышцы, выпрямляющие позвоночник, мышцы живота, а также седалищно-большеберцовые мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet03.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Ноги - Широкие приседания', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/shirokie-prisedaniya', 'Особенностью упражнения являются очень широко расставленные ноги с разведенными в стороны носками. Это дополнительно включает в работу внутренние мышцы бедра.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet04.jpg', 'Ноги - Широкие приседания', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/shirokie-prisedaniya', 'Особенностью упражнения являются очень широко расставленные ноги с разведенными в стороны носками. Это дополнительно включает в работу внутренние мышцы бедра.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet04.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Ноги - Наклонный жим ногами', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/naklonnyj-zhim-nogami', 'Это упражнение можно выполнять людям, которые страдают от болей в спине и поэтому не могут делать приседания. Тем не менее, обязательно прижимайте ягодицы к спинке тренажера.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet05.jpg', 'Ноги - Наклонный жим ногами', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/naklonnyj-zhim-nogami', 'Это упражнение можно выполнять людям, которые страдают от болей в спине и поэтому не могут делать приседания. Тем не менее, обязательно прижимайте ягодицы к спинке тренажера.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet05.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Ноги - Приседания на тренажере НАСК SQUAT', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/prisedaniya-na-trenazhere-nask-squat', 'Это движение создает основную нагрузку на четырехглавые мышцы бедер. Если ступни выставить вперед, то основная нагрузка перейдет на мышцы ягодиц.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet06.jpg', 'Ноги - Приседания на тренажере НАСК SQUAT', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/prisedaniya-na-trenazhere-nask-squat', 'Это движение создает основную нагрузку на четырехглавые мышцы бедер. Если ступни выставить вперед, то основная нагрузка перейдет на мышцы ягодиц.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet06.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Ноги - Разгибание ног', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/razgibanie-nog', 'Это движение лучше всего подходит для изолированной нагрузки на четырехглавые мышцы. Это упражнение обычно рекомендуют начинающим.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet07.jpg', 'Ноги - Разгибание ног', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/razgibanie-nog', 'Это движение лучше всего подходит для изолированной нагрузки на четырехглавые мышцы. Это упражнение обычно рекомендуют начинающим.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet07.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Ноги - Сгибание ног лежа', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/sgibanie-nog-lezha', 'Это упражнение вовлекает в работу всю группу седалищно-подколенных мышц бедер(бицепсы бедра), икроножные мышцы, а также более глубоко расположенные подколенные мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet08.jpg', 'Ноги - Сгибание ног лежа', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/sgibanie-nog-lezha', 'Это упражнение вовлекает в работу всю группу седалищно-подколенных мышц бедер(бицепсы бедра), икроножные мышцы, а также более глубоко расположенные подколенные мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet08.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Ноги - Сгибание одной ноги стоя', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/sgibanie-odnoj-nogi-stoya', 'Это упражнение вовлекает в работу все седалищно-подколенные мышцы бедра (полусухожильные, полуперепончатые, бицепсы бедра - короткие и длинные головки) и в меньшей мере икроножные мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet09.jpg', 'Ноги - Сгибание одной ноги стоя', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/sgibanie-odnoj-nogi-stoya', 'Это упражнение вовлекает в работу все седалищно-подколенные мышцы бедра (полусухожильные, полуперепончатые, бицепсы бедра - короткие и длинные головки) и в меньшей мере икроножные мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet09.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Ноги - Сгибание ног сидя', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/sgibanie-nog-sidya', 'Это упражнение задействует все седалищно-подколенные мышцы бедра, а также в меньшей степени икроножные мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet10.jpg', 'Ноги - Сгибание ног сидя', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/sgibanie-nog-sidya', 'Это упражнение задействует все седалищно-подколенные мышцы бедра, а также в меньшей степени икроножные мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet10.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Ноги - Подъемы торса с добрым утром', 'http://bodysportal.com/bodibilding/uprazhneniya/poyasnitsa/pod-emy-torsa-s-dobrym-utrom', 'Это упражнение, разрабатывающее большую ягодичную мышцу и мышцы спины, оказывает благоприятное воздействие на седалищно-подколенные мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet11.jpg', 'Ноги - Подъемы торса с добрым утром', 'http://bodysportal.com/bodibilding/uprazhneniya/poyasnitsa/pod-emy-torsa-s-dobrym-utrom', 'Это упражнение, разрабатывающее большую ягодичную мышцу и мышцы спины, оказывает благоприятное воздействие на седалищно-подколенные мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet11.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Ноги - Приведение одной ноги стоя', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/privedenie-odnoj-nogi-stoya', 'Это упражнение задействует приводящие мышцы бедра. Оно великолепно формирует внутреннюю поверхность бедра при регулярном его применении.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet12.jpg', 'Ноги - Приведение одной ноги стоя', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/privedenie-odnoj-nogi-stoya', 'Это упражнение задействует приводящие мышцы бедра. Оно великолепно формирует внутреннюю поверхность бедра при регулярном его применении.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet12.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Ноги - Сведение ног сидя', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/svedenie-nog-sidya', 'Это упражнение тренирует приводящие мышцы. Здесь можно использовать более значительный вес отягощения, чем в упражнении с приведением нижнего блока, хотя и с более ограниченным диапазоном движения.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet13.jpg', 'Ноги - Сведение ног сидя', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/svedenie-nog-sidya', 'Это упражнение тренирует приводящие мышцы. Здесь можно использовать более значительный вес отягощения, чем в упражнении с приведением нижнего блока, хотя и с более ограниченным диапазоном движения.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet13.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Ноги - Подъемы на носки стоя', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/pod-emy-na-noski-stoya', 'Это упражнение тренирует трехглавые мышцы голени. Чтобы правильно напрягать эти мышцы, очень важно подниматься на носках как можно выше в каждом повторении движения.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet14.jpg', 'Ноги - Подъемы на носки стоя', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/pod-emy-na-noski-stoya', 'Это упражнение тренирует трехглавые мышцы голени. Чтобы правильно напрягать эти мышцы, очень важно подниматься на носках как можно выше в каждом повторении движения.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet14.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Ноги - Подъем на носок одной ноги стоя', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/pod-em-na-nosok-odnoj-nogi-stoya', 'Это упражнение задействует трицепс голени. Для лучшего результата выполняйте упражнение до появления чувства жжения.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet15.jpg', 'Ноги - Подъем на носок одной ноги стоя', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/pod-em-na-nosok-odnoj-nogi-stoya', 'Это упражнение задействует трицепс голени. Для лучшего результата выполняйте упражнение до появления чувства жжения.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet15.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Ноги - Подъемы на носки в наклоне ослик', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/pod-emy-na-noski-v-naklone-oslik', 'Это - хорошее упражнение для тщательной проработки. Оно задействует трицепс голени и, в частности, икроножные мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet16.jpg', 'Ноги - Подъемы на носки в наклоне ослик', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/pod-emy-na-noski-v-naklone-oslik', 'Это - хорошее упражнение для тщательной проработки. Оно задействует трицепс голени и, в частности, икроножные мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet16.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Ноги - Жимы стопами на тренажере', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/zhimy-stopami-na-trenazhere', 'Это упражнение отлично нагружает икроножные и камбаловидные мышцы голени, за счет чего икра выглядит гораздо объемнее, если смотреть на нее сзади.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet20.jpg', 'Ноги - Жимы стопами на тренажере', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/zhimy-stopami-na-trenazhere', 'Это упражнение отлично нагружает икроножные и камбаловидные мышцы голени, за счет чего икра выглядит гораздо объемнее, если смотреть на нее сзади.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet20.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Ноги - Разгибание голени сидя', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/razgibanie-goleni-sidya', 'Это упражнение задействует преимущественно камбаловидные мышцы. Основная функция камбаловидной мышиы состоит в разгибании голени.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet17.jpg', 'Ноги - Разгибание голени сидя', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/razgibanie-goleni-sidya', 'Это упражнение задействует преимущественно камбаловидные мышцы. Основная функция камбаловидной мышиы состоит в разгибании голени.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet17.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Ноги - Разгибание голени сидя, со штангой на коленях', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/razgibanie-goleni-sidya-so-shtangoj-na-kolenyakh', 'В отличие от проработки камбаловидных мышц на тренажере этот вид упражнения не позволяет использовать тяжелый вес, так как потребует чрезмерных усилий.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet18.jpg', 'Ноги - Разгибание голени сидя, со штангой на коленях', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/razgibanie-goleni-sidya-so-shtangoj-na-kolenyakh', 'В отличие от проработки камбаловидных мышц на тренажере этот вид упражнения не позволяет использовать тяжелый вес, так как потребует чрезмерных усилий.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet18.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Ноги - Подъемы носков голени сидя', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/pod-emy-noskov', 'Это упражнение формирует мышцы передней части голени, делает их более выносливыми и сильными.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet19.jpg', 'Ноги - Подъемы носков голени сидя', 'http://bodysportal.com/bodibilding/uprazhneniya/nogi/pod-emy-noskov', 'Это упражнение формирует мышцы передней части голени, делает их более выносливыми и сильными.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesFeet/miniFeet19.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Ягодицы - Выпады со штангой на плечах', 'http://bodysportal.com/bodibilding/uprazhneniya/yagoditsy/vypady-so-shtangoj-na-plechakh', 'Это упражнение в первую очередь задействует большую ягодичную мышцу.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesButtock/mini_Buttock-1.jpg', 'Ягодицы -  Выпады со штангой на плечах', 'http://bodysportal.com/bodibilding/uprazhneniya/yagoditsy/vypady-so-shtangoj-na-plechakh', 'Это упражнение в первую очередь задействует большую ягодичную мышцу.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesButtock/mini_Buttock-1.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Ягодицы - Выпады с гантелями', 'http://bodysportal.com/bodibilding/uprazhneniya/yagoditsy/vypady-s-gantelyami', 'Это упражнение разрабатывает главным образом большие ягодичные мышцы и четырехглавые мышцы бедер.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesButtock/mini_Buttock-2.jpg', 'Ягодицы -  Выпады с гантелями', 'http://bodysportal.com/bodibilding/uprazhneniya/yagoditsy/vypady-s-gantelyami', 'Это упражнение разрабатывает главным образом большие ягодичные мышцы и четырехглавые мышцы бедер.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesButtock/mini_Buttock-2.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Ягодицы - Махи ногой назад с нижнего блока', 'http://bodysportal.com/bodibilding/uprazhneniya/yagoditsy/makhi-nogoj-nazad-s-nizhnego-bloka', 'Это упражнение вовлекает в работу главным образом большую ягодичную мышцу и в меньшей степени седалищно-большеберцовую мышцу, исключая короткую головку бицепса бедра.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesButtock/mini_Buttock-3.jpg', 'Ягодицы -  Махи ногой назад с нижнего блока', 'http://bodysportal.com/bodibilding/uprazhneniya/yagoditsy/makhi-nogoj-nazad-s-nizhnego-bloka', 'Это упражнение вовлекает в работу главным образом большую ягодичную мышцу и в меньшей степени седалищно-большеберцовую мышцу, исключая короткую головку бицепса бедра.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesButtock/mini_Buttock-3.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Ягодицы - Махи ногой назад с рычагом тренажера', 'http://bodysportal.com/bodibilding/uprazhneniya/yagoditsy/makhi-nogoj-nazad-s-rychagom-trenazhera', 'Это упражнение задействует главным образом большую ягодичную мышцу, а также в меньшей степени полусухожильную, полуперепончатую мышцы и длинную головку бицепса бедра.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesButtock/mini_Buttock-4.jpg', 'Ягодицы -  Махи ногой назад с рычагом тренажера', 'http://bodysportal.com/bodibilding/uprazhneniya/yagoditsy/makhi-nogoj-nazad-s-rychagom-trenazhera', 'Это упражнение задействует главным образом большую ягодичную мышцу, а также в меньшей степени полусухожильную, полуперепончатую мышцы и длинную головку бицепса бедра.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesButtock/mini_Buttock-4.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Ягодицы - Махи ногой назад на полу', 'http://bodysportal.com/bodibilding/uprazhneniya/yagoditsy/makhi-nogoj-nazad-na-polu', 'Это упражнение, выполняемое прямой ногой, разрабатывает седалищно-подколенные мышцы и большую ягодичную мышцу. При согнутой в колене ноге разрабатывается только большая ягодичная мышца, но менее интенсивно.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesButtock/mini_Buttock-5.jpg', 'Ягодицы -  Махи ногой назад на полу', 'http://bodysportal.com/bodibilding/uprazhneniya/yagoditsy/makhi-nogoj-nazad-na-polu', 'Это упражнение, выполняемое прямой ногой, разрабатывает седалищно-подколенные мышцы и большую ягодичную мышцу. При согнутой в колене ноге разрабатывается только большая ягодичная мышца, но менее интенсивно.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesButtock/mini_Buttock-5.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Ягодицы - Мостик лежа', 'http://bodysportal.com/bodibilding/uprazhneniya/yagoditsy/mostik-lezha', 'Это упражнение задействует главным образом седалищно-подколенные и большие ягодичные мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesButtock/mini_Buttock-6.jpg', 'Ягодицы -  Мостик лежа', 'http://bodysportal.com/bodibilding/uprazhneniya/yagoditsy/mostik-lezha', 'Это упражнение задействует главным образом седалищно-подколенные и большие ягодичные мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesButtock/mini_Buttock-6.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Ягодицы - Махи ногой в сторону с нижнего блока', 'http://bodysportal.com/bodibilding/uprazhneniya/yagoditsy/makhi-nogoj-v-storonu-s-nizhnego-bloka', 'Это упражнение вовлекает в работу среднюю ягодичную мышцу и расположенную глубже малую ягодичную мышцу.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesButtock/mini_Buttock-7.jpg', 'Ягодицы -  Махи ногой в сторону с нижнего блока', 'http://bodysportal.com/bodibilding/uprazhneniya/yagoditsy/makhi-nogoj-v-storonu-s-nizhnego-bloka', 'Это упражнение вовлекает в работу среднюю ягодичную мышцу и расположенную глубже малую ягодичную мышцу.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesButtock/mini_Buttock-7.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Ягодицы - Махи ногой в сторону с рычагом тренажера', 'http://bodysportal.com/bodibilding/uprazhneniya/yagoditsy/makhi-nogoj-v-storonu-s-rychagom-trenazhera', 'Это упражнение прекрасно подходит для формирования средней ягодичной мышцы и малой ягодичной мышцы, расположенной глубже. Для достижения лучших результатов советуем выполнять это упражнение чаще и с многократными повторениями.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesButtock/mini_Buttock-8.jpg', 'Ягодицы -  Махи ногой в сторону с рычагом тренажера', 'http://bodysportal.com/bodibilding/uprazhneniya/yagoditsy/makhi-nogoj-v-storonu-s-rychagom-trenazhera', 'Это упражнение прекрасно подходит для формирования средней ягодичной мышцы и малой ягодичной мышцы, расположенной глубже. Для достижения лучших результатов советуем выполнять это упражнение чаще и с многократными повторениями.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesButtock/mini_Buttock-8.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Ягодицы - Махи ногой в сторону, лежа на боку', 'http://bodysportal.com/bodibilding/uprazhneniya/yagoditsy/makhi-nogoj-v-storonu-lezha-na-boku', 'Это упражнение задействует средние и малые ягодичные мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesButtock/mini_Buttock-9.jpg', 'Ягодицы -  Махи ногой в сторону, лежа на боку', 'http://bodysportal.com/bodibilding/uprazhneniya/yagoditsy/makhi-nogoj-v-storonu-lezha-na-boku', 'Это упражнение задействует средние и малые ягодичные мышцы.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesButtock/mini_Buttock-9.jpg')"
CONN.execute "INSERT INTO dictitems (name, url, description, img, name_ru, url_ru, desc_ru, img_ru) VALUES ('Ягодицы - Разведение ног на тренажере', 'http://bodysportal.com/bodibilding/uprazhneniya/yagoditsy/razvedenie-nog-na-trenazhere', 'Это упражнение великолепно подходит для женщин, поскольку повышенный мышечный тонус бедер придает им округлость, что позволяет выделить талию, которая станет казаться более тонкой.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesButtock/mini_Buttock-10.jpg', 'Ягодицы -  Разведение ног на тренажере', 'http://bodysportal.com/bodibilding/uprazhneniya/yagoditsy/razvedenie-nog-na-trenazhere', 'Это упражнение великолепно подходит для женщин, поскольку повышенный мышечный тонус бедер придает им округлость, что позволяет выделить талию, которая станет казаться более тонкой.', 'http://bodysportal.com/images/bodibilding/exercises/exercisesButtock/mini_Buttock-10.jpg')"
